import './App.css';
import ShapeGrid from './component/ShapeGrid';
function App() {
  return (
    <div className="App">
      <div style={{ width: '100%', height: '100%', position: 'f' }}>
  <ShapeGrid
    speed={0.5}
    squareSize={40}
    direction="diagonal"
    borderColor="#000000"
    hoverFillColor="#040101"
    shape="square"
    hoverTrailAmount={0}
  />
</div>
</div>
  );
}

export default App;
